if(!customElements.get('cma-field-config')){class CmaFieldConfig extends HTMLElement{static get observedAttributes(){return['readonly']}
constructor(){super();this._fields=[];this._parameters=[];this._sorting=[];this._grouping=[];this._listenersAttached=!1;this._searchFilter='';this._showSelectedOnly=!1}
connectedCallback(){this._render()}
attributeChangedCallback(name,oldValue,newValue){if(oldValue===newValue)return;if(name==='readonly'){this._updateReadonlyState()}}
static _typeTranslations={'text':'tekst','number':'getal','date':'datum','boolean':'ja/nee','binary':'binair'};_translateType(typeCategory){return CmaFieldConfig._typeTranslations[typeCategory]||typeCategory}
_displayTableName(tableName){return(typeof CMA!=='undefined'&&CMA.displayTableName)?CMA.displayTableName(tableName):tableName||''}
setFields(fields){this._fields=(fields||[]).map((f,index)=>{const fieldName=f.field||f.name||'';const typeCategory=f.typeCategory||'text';let alias=f.alias||fieldName;if(typeCategory==='number'&&fieldName.toLowerCase().startsWith('fk')&&!f.alias){alias=fieldName.substring(2)}
return{table:f.table||'',field:fieldName,alias:alias,dataType:f.dataType||0,typeCategory:typeCategory,visible:f.visible!==!1,showTotal:f.showTotal||!1,_index:index}});this._renderTable();this._updateSelectAllState();if(!this._listenersAttached){this._setupEventListeners()}}
getFields(){return this._fields.map(f=>({table:f.table,field:f.field,alias:f.alias,dataType:f.dataType,typeCategory:f.typeCategory,visible:f.visible,showTotal:f.showTotal}))}
getVisibleFields(){return this.getFields().filter(f=>f.visible)}
setFieldProperty(index,prop,value){if(index>=0&&index<this._fields.length){this._fields[index][prop]=value;this._dispatchFieldChange(index,prop,value)}}
setParameters(params){this._parameters=params||[]}
getParameters(){return this._parameters}
setSorting(sorting){this._sorting=sorting||[];this._renderTable()}
setGrouping(grouping){this._grouping=grouping||[];this._renderTable()}
_getFieldSortDirection(table,field){const sortItem=this._sorting.find(s=>s.table===table&&s.field===field);return sortItem?(sortItem.direction||'ASC'):null}
_isFieldGrouped(table,field){return this._grouping.some(g=>g.table===table&&g.field===field)}
selectAll(){this._fields.forEach(field=>{field.visible=!0});this._renderTable();this._updateSelectAllState();this._dispatchChange()}
deselectAll(){this._fields.forEach(field=>{field.visible=!1});this._renderTable();this._updateSelectAllState();this._dispatchChange()}
setSearchFilter(filter){this._searchFilter=(filter||'').toLowerCase().trim();this._renderTable()}
_render(){this.innerHTML=`
            <style>
                cma-field-config {
                    display: block;
                    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
                    font-size: var(--font-size);
                }

                * {
                    box-sizing: border-box;
                }

                /* Linearicons inherited from page CSS */

                .field-config-container {
                    border: 1px solid var(--border-color, #ddd);
                    border-top: 0;
                    border-radius: 4px;
                    overflow: hidden;
                    height: 100%;
                    display: flex;
                    flex-direction: column;
                }

                .field-config-table {
                    width: 100%;
                    border-collapse: collapse;
                }

                .field-config-table th,
                .field-config-table td {
                    padding: 8px 10px;
                    text-align: left;
                    border-bottom: 1px solid var(--border-light, #eee);
                }

                .field-config-table th {
                    background: var(--bg-surface-alt, #f8f9fa);
                    font-weight: 600;
                    font-size: var(--font-size-sm);
                    position: sticky;
                    top: 0;
                    z-index: 1;
                }

                .field-config-table tbody tr:hover {
                    background: var(--bg-hover);
                    outline: 1px solid var(--color-primary, #204496);
                    outline-offset: -1px;
                }

                /* Hidden field: no visual change, checkbox state is sufficient */

                /* Ensure visibility checkbox is always clickable */
                .visibility-checkbox {
                    cursor: pointer;
                    pointer-events: auto !important;
                }

                .col-checkbox {
                    width: 50px;
                    text-align: center !important;
                }

                .select-all-checkbox {
                    width: 18px;
                    height: 18px;
                    cursor: pointer;
                }

                .col-field {
                    width: 200px;
                }

                .col-alias {
                    width: 200px;
                }

                .col-type {
                    width: 70px;
                }

                .col-total {
                    width: 60px;
                    text-align: center !important;
                }

                .col-total input[type="checkbox"] {
                    width: 16px;
                    height: 16px;
                    cursor: pointer;
                }

                .col-total input[type="checkbox"]:disabled {
                    cursor: not-allowed;
                    opacity: 0.3;
                }

                .col-filter {
                    width: 50px;
                    text-align: center !important;
                }

                .add-filter-btn {
                    width: 28px;
                    height: 28px;
                    padding: 0;
                    border: 1px solid var(--border-color, #ddd);
                    border-radius: 4px;
                    background: var(--bg-surface, #fff);
                    cursor: pointer;
                    color: var(--text-muted, #666);
                    display: inline-flex;
                    align-items: center;
                    justify-content: center;
                    font-size: var(--font-size-lg);
                    transition: all 0.15s ease;
                }

                .add-filter-btn:hover {
                    background: var(--bg-hover, #eef6ff);
                    border-color: var(--color-primary, #204496);
                    color: var(--color-primary, #204496);
                }

                .add-filter-btn:active {
                    transform: scale(0.95);
                }

                .field-table {
                    font-size: var(--font-size-xs);
                    color: var(--text-muted, #888);
                }

                .field-column {
                    font-weight: 500;
                }

                .field-indicator {
                    display: inline-block;
                    margin-left: 6px;
                    font-size: var(--font-size-2xs);
                    padding: 1px 4px;
                    border-radius: 3px;
                    vertical-align: middle;
                }

                .sort-indicator {
                    background: var(--color-primary-light, #e3f2fd);
                    color: #ffffff;
                    font-weight: 600;
                }

                .group-indicator {
                    background: var(--color-success-light, #e8f5e9);
                    color: var(--color-success, #2e7d32);
                }

                .group-indicator .lnr {
                    font-size: var(--font-size-xs);
                }

                .type-label {
                    font-size: var(--font-size-xs);
                    color: var(--text-muted, #888);
                }

                .alias-input {
                    width: 200px;
                    padding: 6px 10px;
                    border: 1px solid #ddd;
                    border-radius: 4px;
                    font-size: var(--font-size);
                }

                .alias-input:focus {
                    outline: none;
                    border-color: #204496;
                    box-shadow: 0 0 0 2px rgba(32, 68, 150, 0.1);
                }


                .visibility-checkbox {
                    width: 18px;
                    height: 18px;
                    cursor: pointer;
                }

                .empty-state {
                    padding: 40px 20px;
                    text-align: center;
                    color: #888;
                }

                .empty-state .empty-icon {
                    font-size: 36px;
                    margin-bottom: 10px;
                    opacity: 0.5;
                    color: var(--text-muted, #888);
                }

                .empty-state .empty-text {
                    font-size: var(--font-size-md);
                }

                /* Scrollable body */
                .table-wrapper {
                    flex: 1;
                    overflow-y: auto;
                }

                /* Readonly state */
                cma-field-config[readonly] .alias-input,
                cma-field-config[readonly] .filter-operator,
                cma-field-config[readonly] .filter-value,
                cma-field-config[readonly] .visibility-checkbox {
                    pointer-events: none;
                    opacity: 0.7;
                }
            </style>
            <div class="field-config-container">
                <div class="table-wrapper">
                    <table class="field-config-table">
                        <thead>
                            <tr>
                                <th class="col-checkbox">
                                    <input type="checkbox" class="select-all-checkbox" id="selectAllCheckbox" title="Alles selecteren/deselecteren">
                                </th>
                                <th class="col-field">Veld</th>
                                <th class="col-alias">Alias</th>
                                <th class="col-type">Type</th>
                                <th class="col-total">Totaal</th>
                                <th class="col-filter">Filter</th>
                            </tr>
                        </thead>
                        <tbody id="tableBody">
                        </tbody>
                    </table>
                </div>
            </div>
        `;this._renderTable()}
_renderTable(){const tbody=this.querySelector('#tableBody');if(!tbody)return;if(this._fields.length===0){tbody.innerHTML=`
                <tr>
                    <td colspan="6">
                        <div class="empty-state">
                            <span class="empty-icon lnr lnr-list"></span>
                            <div class="empty-text">Selecteer eerst tabellen om velden te configureren</div>
                        </div>
                    </td>
                </tr>
            `;return}
let filteredFields=this._fields.map((field,index)=>({field,index}));if(this._searchFilter){filteredFields=filteredFields.filter(({field})=>{const searchTerm=this._searchFilter;return field.field.toLowerCase().includes(searchTerm)||field.table.toLowerCase().includes(searchTerm)||(field.alias&&field.alias.toLowerCase().includes(searchTerm))})}
if(this._showSelectedOnly){filteredFields=filteredFields.filter(({field})=>field.visible)}
if(filteredFields.length===0){tbody.innerHTML=`
                <tr>
                    <td colspan="6">
                        <div class="empty-state">
                            <span class="empty-icon lnr lnr-magnifier"></span>
                            <div class="empty-text">Geen velden gevonden voor "${this._escapeHtml(this._searchFilter)}"</div>
                        </div>
                    </td>
                </tr>
            `;return}
const uniqueTables=new Set(this._fields.map(f=>f.table));const showTableName=uniqueTables.size>1;tbody.innerHTML=filteredFields.map(({field,index})=>{const sortDir=this._getFieldSortDirection(field.table,field.field);const isGrouped=this._isFieldGrouped(field.table,field.field);return `
            <tr data-index="${index}" class="${field.visible ? '' : 'hidden-field'}">
                <td class="col-checkbox">
                    <input type="checkbox" class="visibility-checkbox"
                           ${field.visible ? 'checked' : ''}
                           data-field="visible">
                </td>
                <td class="col-field">
                    <div class="field-name">
                        ${showTableName ? `<span class="field-table">${this._escapeHtml(this._displayTableName(field.table))}.</span>` : ''}
                        <span class="field-column">${this._escapeHtml(field.field)}</span>
                        ${sortDir ? `<span class="field-indicator sort-indicator" title="Gesorteerd ${sortDir.toUpperCase() === 'ASC' ? 'oplopend' : 'aflopend'}">${sortDir.toUpperCase()==='ASC'?'A↓Z':'Z↓A'}</span>` : ''}
                        ${isGrouped ? `<span class="field-indicator group-indicator" title="Gegroepeerd"><span class="lnr lnr-layers"></span></span>` : ''}
                    </div>
                </td>
                <td class="col-alias">
                    <input type="text" class="alias-input"
                           value="${this._escapeHtml(field.alias)}"
                           data-field="alias"
                           placeholder="Alias">
                </td>
                <td class="col-type">
                    <span class="type-label">${this._escapeHtml(this._translateType(field.typeCategory))}</span>
                </td>
                <td class="col-total">
                    <input type="checkbox" class="total-checkbox"
                           ${field.showTotal ? 'checked' : ''}
                           ${this._canShowTotal(field) ? '' : 'disabled'}
                           data-field="showTotal"
                           title="${this._canShowTotal(field) ? 'Toon totaal voor dit veld' : 'Niet beschikbaar voor dit veld'}">
                </td>
                <td class="col-filter">
                    <button type="button" class="add-filter-btn"
                            data-table="${this._escapeHtml(field.table)}"
                            data-field="${this._escapeHtml(field.field)}"
                            data-alias="${this._escapeHtml(field.alias)}"
                            data-datatype="${field.dataType}"
                            data-typecategory="${this._escapeHtml(field.typeCategory)}"
                            title="Filter toevoegen">+</button>
                </td>
            </tr>
        `}).join('')}
setShowSelectedOnly(showSelectedOnly){this._showSelectedOnly=showSelectedOnly;this._renderTable()}
_setupEventListeners(){const selectAllCheckbox=this.querySelector('#selectAllCheckbox');if(selectAllCheckbox){selectAllCheckbox.addEventListener('change',(e)=>{const visible=e.target.checked;this._fields.forEach((field,index)=>{field.visible=visible});this._renderTable();this._updateSelectAllState();this._dispatchChange()})}
this.addEventListener('change',(e)=>{const row=e.target.closest('tr');if(!row)return;const index=parseInt(row.dataset.index,10);if(isNaN(index))return;const fieldName=e.target.dataset.field;if(fieldName==='visible'){if(typeof cmaLog!=='undefined'){cmaLog.log('cma-field-config: visibility checkbox clicked, index:',index,'checked:',e.target.checked)}
this._fields[index].visible=e.target.checked;row.classList.toggle('hidden-field',!e.target.checked);this._updateSelectAllState();this._dispatchFieldChange(index,'visible',e.target.checked);this._dispatchChange()}else if(fieldName==='alias'){const sanitized=(typeof CMA!=='undefined'&&CMA.sanitizeAlias)?CMA.sanitizeAlias(e.target.value):e.target.value.replace(/\s+/g,'_');e.target.value=sanitized;this._fields[index].alias=sanitized;this._dispatchFieldChange(index,'alias',sanitized)}else if(fieldName==='showTotal'){this._fields[index].showTotal=e.target.checked;this._dispatchFieldChange(index,'showTotal',e.target.checked)}});this.addEventListener('input',(e)=>{if(e.target.dataset.field==='alias'){const row=e.target.closest('tr');if(!row)return;const index=parseInt(row.dataset.index,10);if(isNaN(index))return;const sanitized=(typeof CMA!=='undefined'&&CMA.sanitizeAlias)?CMA.sanitizeAlias(e.target.value):e.target.value.replace(/\s+/g,'_');e.target.value=sanitized;this._fields[index].alias=sanitized}});this.addEventListener('click',(e)=>{if(e.target.classList.contains('add-filter-btn')){e.stopPropagation();const btn=e.target;this.dispatchEvent(new CustomEvent('add-condition',{bubbles:!0,composed:!0,detail:{table:btn.dataset.table,field:btn.dataset.field,alias:btn.dataset.alias,dataType:parseInt(btn.dataset.datatype,10)||0,typeCategory:btn.dataset.typecategory||'text'}}))}});this._listenersAttached=!0}
_canShowTotal(field){if(field.typeCategory!=='number')return!1;const name=field.field.toLowerCase();if(name.startsWith('fk'))return!1;if(name.endsWith('id'))return!1;if(name==='id')return!1;return!0}
_updateSelectAllState(){const selectAllCheckbox=this.querySelector('#selectAllCheckbox');if(!selectAllCheckbox||this._fields.length===0)return;const visibleCount=this._fields.filter(f=>f.visible).length;const totalCount=this._fields.length;if(visibleCount===0){selectAllCheckbox.checked=!1;selectAllCheckbox.indeterminate=!1}else if(visibleCount===totalCount){selectAllCheckbox.checked=!0;selectAllCheckbox.indeterminate=!1}else{selectAllCheckbox.checked=!1;selectAllCheckbox.indeterminate=!0}}
_dispatchChange(){if(typeof cmaLog!=='undefined'){cmaLog.log('cma-field-config: dispatching change event',this.getFields().length,'fields')}
this.dispatchEvent(new CustomEvent('change',{bubbles:!0,composed:!0,detail:{fields:this.getFields()}}))}
_dispatchFieldChange(index,property,value){this.dispatchEvent(new CustomEvent('field-change',{bubbles:!0,composed:!0,detail:{index,property,value,field:this._fields[index]}}));this.dispatchEvent(new CustomEvent('change',{bubbles:!0,composed:!0,detail:{fields:this.getFields()}}))}
_updateReadonlyState(){}
_escapeHtml(text){if(text===null||text===undefined)return'';const div=document.createElement('div');div.textContent=text;return div.innerHTML}}
customElements.define('cma-field-config',CmaFieldConfig)}
